#include<cstdio>
#include<vector>
#define rep(a,b,c) for(int c(a);c<=(b);++c)
#define drep(a,b,c) for(int c(a);c>=(b);--c)
#define grep(b,c) for(int c(head[b]);c;c=nxt[c])
inline int read()
{
	int res=0;char ch=getchar();while(ch<'0'||ch>'9')ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();return res;
}
const int N=2e5+10,M=4e5+10;int head[N],des[M],nxt[M],cgt=1,fa[N],n,m;bool vis[N],flag,Vis[N];
inline void ins(int x,int y){nxt[++cgt]=head[x];des[head[x]=cgt]=y;nxt[++cgt]=head[y];des[head[y]=cgt]=x;}
std::vector<int> p[3];int cu[M],cv[M],cdt,tag[N],stk[N],top;
inline void dfs(int u)
{
//	printf("dfs %d\n",u);
	vis[u]=true;grep(u,i)if(!Vis[i>>1])
	{
		Vis[i>>1]=true;int v=des[i];
		if(!vis[v]){fa[v]=u;dfs(v);}
		else
		{
			int x=u;cu[++cdt]=u;cv[cdt]=v;
			while(x!=v&&!tag[x])tag[x]=cdt,x=fa[x];
//			printf("QAQ %d %d %d %d %d-->%d\n",tag[x],cdt,x,v,u,v);
			if(x==v)continue;p[0].push_back(x);
			puts("YES");
			int y=x;while(y!=v&&tag[fa[y]]==tag[x])p[0].push_back(y=fa[y]);
			if(y!=v)p[0].push_back(y=fa[y]);
			p[1].push_back(x);
//			printf("fa[51] = %d\n",fa[51]);
//			printf("fa[40] = %d\n",fa[40]);
//			printf("fa[41] = %d\n",fa[41]);
//			printf("QwQ %d %d %d %d %d %d\n",x,y,u,v,cu[tag[x]],cv[tag[x]]);
			int c=u;while(c!=x)stk[++top]=c,c=fa[c];
			while(top)p[1].push_back(stk[top--]);
			c=y;while(c!=v)stk[++top]=c=fa[c];
			while(top)p[1].push_back(stk[top--]);
			p[1].push_back(y);
			
			int qu=cu[tag[x]],qv=cv[tag[x]];
			p[2].push_back(x);
			c=qu;while(c!=x)stk[++top]=c,c=fa[c];
			while(top)p[2].push_back(stk[top--]);
			c=y;while(c!=qv)stk[++top]=c=fa[c];
			while(top)p[2].push_back(stk[top--]);
			p[2].push_back(y);
			flag=true;return;
		}
		if(flag)return;
	}
}
int main()
{
	n=read();m=read();rep(1,m,i)ins(read(),read());
	rep(1,n,i)if(!vis[i]){dfs(i);if(flag)break;}
	if(!flag)puts("NO");
	else rep(0,2,i)
	{
		printf("%d ",int(p[i].size()));
		for(int v:p[i])printf("%d ",v);putchar('\n');
	}
}
